mapper.update:
   		/** bondChkScheduleMapper.updateMspBondDtlPay */
   		UPDATE MSP_BOND_DTL 
		SET 
			  PAY_YM = SUBSTR(#{payDt}, 0, 6)
			  , PAY_AMT = #{payAmt}
			  , PAY_DT = #{payDt}
		WHERE 	1 = 1
				AND 	BOND_SEQ_NUM = #{bondSeqNum}
				AND		CONTRACT_NUM = #{contractNum}
				AND 	BILL_YM = #{billYm}

   		/** bondChkScheduleMapper.updateMspBondMstPay */
   		UPDATE MSP_BOND_MST 
		SET 
			  	PAY_AMT = (SELECT NVL(SUM(PAY_AMT), 0) FROM MSP_BOND_DTL WHERE BOND_SEQ_NUM = #{bondSeqNum})
		WHERE 	1 = 1
				AND 	BOND_SEQ_NUM = #{bondSeqNum}

   		/** bondChkScheduleMapper.updateMspBondMstFullPay */
   		UPDATE MSP_BOND_MST
		SET 
			  FULL_PAY_YN = 'Y'

		WHERE 	1 = 1
				AND	CONTRACT_NUM = #{contractNum}

   		/** bondChkScheduleMapper.updateMspBondStaticMst */
   		UPDATE 
   				MSP_BOND_STATIC_MST
		SET 
			  	RCV_AMT = #{rcvAmt}

		WHERE 	1 = 1
				AND		OPEN_YM = #{openYm}

   		/** bondChkScheduleMapper.updateMspBondStaticDtl */
   		UPDATE 
   				MSP_BOND_STATIC_DTL
		SET 
			  	RCV_AMT = #{rcvAmt}

		WHERE 	1 = 1
				AND		OPEN_YM = #{openYm}
				AND		BILL_YM = #{billYm}

   		/** bondChkScheduleMapper.updateMspBondStaticDtlErly */
   		UPDATE
				MSP_BOND_STATIC_DTL
		SET
				ERLY_RFND_CNT = #{erlyRfndCnt}
				, ERLY_RFND_AMT = #{erlyRfndAmt}
		WHERE	1 =1
				AND OPEN_YM = #{openYm}
				AND BILL_YM = TO_CHAR(ADD_MONTHS(SYSDATE, -2), 'YYYYMM')

   		/** bondChkScheduleMapper.updateBondSaleDtlPay */
   		UPDATE MSP_BOND_SALE_DTL 
		SET 
			  PAY_YM = SUBSTR(#{payDt}, 0, 6)
			  , PAY_AMT = #{payAmt}
		WHERE 	1 = 1
				AND		CONTRACT_NUM = #{contractNum}
				AND 	BILL_YM = #{billYm}

   		/** bondChkScheduleMapper.updateBondSaleCntrPay */
   		UPDATE MSP_BOND_SALE_CNTR 
		SET 
			  	PAY_AMT = (SELECT NVL(SUM(PAY_AMT),0) FROM MSP_BOND_SALE_DTL WHERE CONTRACT_NUM = #{contractNum})
		WHERE 	1 = 1
				AND 	CONTRACT_NUM = #{contractNum}

   		/** bondChkScheduleMapper.updateMspBondMstTmnt */
   		UPDATE 
   				MSP_BOND_MST 
		SET 
			  	TMNT_DT = #{tmntDt}
		WHERE 	1 = 1
				AND 	CONTRACT_NUM = #{contractNum}

   		/** bondChkScheduleMapper.updateMspBondStaticDtlTmnt */
   		UPDATE 
   				MSP_BOND_STATIC_DTL 
		SET 
			  	CAN_CNT = #{canCnt}
		WHERE 	1 = 1
				AND 	OPEN_YM = #{openYm}
				AND		BILL_YM = TO_CHAR(ADD_MONTHS(SYSDATE, -2), 'YYYYMM')

   		/** bondChkScheduleMapper.updateMspBondStaticDtlDly */
   		UPDATE 
   				MSP_BOND_STATIC_DTL 
		SET 
			  	DLY_ADD_AMT = #{dlyAddAmt}
		WHERE 	1 = 1
				AND 	OPEN_YM = #{openYm}
				AND BILL_YM = TO_CHAR(ADD_MONTHS(SYSDATE, -2), 'YYYYMM')

   		/** bondChkScheduleMapper.updateMspBondStaticDtlDlyCnt */
   		UPDATE 
   				MSP_BOND_STATIC_DTL 
		SET 
			  	DLY_CNT = #{dlyCnt}
		WHERE 	1 = 1
				AND 	OPEN_YM = #{openYm}
				AND BILL_YM = TO_CHAR(ADD_MONTHS(SYSDATE, -2), 'YYYYMM')

   		/** bondChkScheduleMapper.updateMspBondStaticDtlAdj */
   		UPDATE 
   				MSP_BOND_STATIC_DTL 
		SET 
			  	ADJ_CNT = #adjCnt}
			  	, ADJ_AMT = #{adjAmt}
		WHERE 	1 = 1
				AND 	OPEN_YM = #{openYm}
				AND BILL_YM = TO_CHAR(ADD_MONTHS(SYSDATE, -2), 'YYYYMM')

   		/** bondChkScheduleMapper.updateMspBondStaticDtlMnth */
   		UPDATE 
   				MSP_BOND_STATIC_DTL 
		SET 
			  	MNTH_FST_AMT = #{mnthFstAmt}
				, MNTH_FST_CNT = #{mnthFstCnt}
				, MNTH_LST_AMT = #{mnthLstAmt} 

		WHERE 	1 = 1     
				AND		OPEN_YM = #{openYm}   
				AND     BILL_YM = TO_CHAR(ADD_MONTHS(SYSDATE, -2), 'YYYYMM')

   		/** bondChkScheduleMapper.updateMspBondStaticDtlMnthDly */
   		UPDATE 
   				MSP_BOND_STATIC_DTL     
		SET     
				DLY_MON_1            =  #{dlyMon1}
				, DLY_MON_2          =  #{dlyMon2}
				, DLY_MON_3          =  #{dlyMon3}
				, DLY_MON_4          =  #{dlyMon4}
				, DLY_MON_5          =  #{dlyMon5}
				, DLY_MON_6          =  #{dlyMon6}
				, DLY_MON_7          =  #{dlyMon7}
				, DLY_MON_8          =  #{dlyMon8}
				, DLY_MON_9          =  #{dlyMon9}
				, DLY_MON_10        =  #{dlyMon10}
				, DLY_MON_11        =  #{dlyMon11} 

		WHERE 	1 = 1     
				AND		OPEN_YM = #{openYm}   
				AND     BILL_YM = TO_CHAR(ADD_MONTHS(SYSDATE, -2), 'YYYYMM')

   		/** bondChkScheduleMapper.updateMspBondStaticDtlMnthDly2 */
   		UPDATE 
   				MSP_BOND_STATIC_DTL     
		SET     
				DLY_MON_12            =  #{dlyMon12}
		WHERE 	1 = 1     
				AND		OPEN_YM = #{openYm}   
				AND     BILL_YM = TO_CHAR(ADD_MONTHS(SYSDATE, -2), 'YYYYMM')

   		/** bondChkScheduleMapper.updateMspBondStaticDtlNotBillAmt */
   		UPDATE 
   				MSP_BOND_STATIC_DTL     
		SET     
				DLY_NOT_BILL_AMT            =  #{dlyNotBillAmt}
		WHERE 	1 = 1     
				AND		OPEN_YM = #{openYm}   
				AND     BILL_YM = TO_CHAR(ADD_MONTHS(SYSDATE, -2), 'YYYYMM')

   		/** bondChkScheduleMapper.updateMspBondStaticDtlNmlAmt */
   		UPDATE 
   				MSP_BOND_STATIC_DTL     
		SET     
				NML_BILL_AMT            =  #{nmlBillAmt}
				, RCV_AMT            =  RCV_AMT - ERLY_RFND_AMT
		WHERE 	1 = 1     
				AND		OPEN_YM = #{openYm}
				AND     BILL_YM = TO_CHAR(ADD_MONTHS(SYSDATE, -2), 'YYYYMM')

   		/** bondChkScheduleMapper."updateMspBondStaticDtlDlyBillAmt" */
   		UPDATE 
   				MSP_BOND_STATIC_DTL     
		SET     
				DLY_BILL_AMT            =  #{dlyBillAmt}
		WHERE 	1 = 1     
				AND		OPEN_YM = #{openYm}
				AND     BILL_YM = TO_CHAR(ADD_MONTHS(SYSDATE, -2), 'YYYYMM')

   		/** bondChkScheduleMapper.updateMspBondStaticDtlDlyPayAmt */
   		UPDATE 
   				MSP_BOND_STATIC_DTL     
		SET     
				DLY_PAY_AMT            =  #{dlyPayAmt}
		WHERE 	1 = 1     
				AND		OPEN_YM = #{openYm}
				AND     BILL_YM = TO_CHAR(ADD_MONTHS(SYSDATE, -2), 'YYYYMM')
